hooks.command:
node -e "
const chunks = [];
process.stdin.on('data', d => chunks.push(d));
process.stdin.on('end', () => {
  const input = JSON.parse(Buffer.concat(chunks).toString());
  const cmd = input.tool_input?.command || '';
  if (!/git\s+commit\b/.test(cmd)) process.exit(0);
  const { execSync } = require('child_process');
  const fs = require('fs');
  const path = require('path');
  const os = require('os');
  // A leading 'cd <path>' in the command is the real target directory:
  // Claude Code prefixes this whenever the session's tracked cwd differs
  // from this hook process's own cwd (e.g. a sibling repo worktree) — the
  // hook process itself always inherits the primary working directory,
  // never the command's actual target.
  function resolveTargetDir() {
    const m = cmd.match(/^\s*cd\s+('([^']+)'|(\S+))\s*(?:&&|;|\n|$)/);
    if (m) {
      let dir = m[2] || m[3];
      if (dir.startsWith('~')) dir = path.join(os.homedir(), dir.slice(1));
      dir = path.resolve(process.cwd(), dir);
      if (fs.existsSync(dir)) return dir;
    }
    return process.cwd();
  }
  const targetDir = resolveTargetDir();
  let repoRoot;
  try {
    repoRoot = execSync('git rev-parse --show-toplevel', { cwd: targetDir, encoding: 'utf8' }).trim();
  } catch {
    process.exit(0);
  }
  // Only this repo's own bun build/lint/typecheck applies — skip silently
  // for any other repo (e.g. a sibling Go/Python repo touched in the same session).
  const pkgPath = path.join(repoRoot, 'package.json');
  if (!fs.existsSync(pkgPath)) process.exit(0);
  let pkg;
  try {
    pkg = JSON.parse(fs.readFileSync(pkgPath, 'utf8'));
  } catch {
    process.exit(0);
  }
  if (pkg.name !== 'hyperframes-monorepo') process.exit(0);
  const steps = [
    ['bun run build', 'Build'],
    ['bun run lint', 'Lint'],
    ['bun run --filter \'*\' typecheck 2>&1 | grep -v \'vitest\\|test\\.ts\' || true', 'Typecheck'],
  ];
  const failures = [];
  for (const [script, label] of steps) {
    try {
      execSync(script, { cwd: repoRoot, stdio: 'pipe' });
    } catch (e) {
      failures.push(label + ':\n' + (e.stdout?.toString() || e.message).slice(0, 400));
    }
  }
  if (failures.length > 0) {
    process.stdout.write(JSON.stringify({
      continue: false,
      stopReason: '❌ Pre-commit checks failed:\n\n' + failures.join('\n\n') + '\n\nFix the issues above before committing.',
    }));
  }
});"
